/* Worked example spec for PanelProof — the Dinner Bell (AMP-049) cheese line.
   This is the "source of truth" half of a proof job: per-file expected frame contents.
   Pair it with the shared profile frame map (see Data Merge's example-profile-nutrition.jsxinc).
   The ext() helper builds product variants from a base without repeating every field. */
function ext(b,o){ var r={},k; for(k in b)r[k]=b[k]; for(k in o)r[k]=o[k]; return r; }

var CHE = { cal:"110", totfat:"9g", totfat_dv:"12%", satfat:"Saturated Fat 5g", satfat_dv:"25%",
  chol:"30mg", chol_dv:"10%", sodium:"190mg", sodium_dv:"8%", carb:"1g", sugars:"0g", protein:"6g",
  vitd:"Vitamin D 0mcg", calcium:"Calcium 201mg", iron:"0mg", potassium:"Potassium 22mg",
  ingredients:"INGREDIENTS: PASTEURIZED MILK, CHEESE CULTURES, SALT, ENZYMES, ANNATTO VEGETABLE COLOR (IF COLORED)" };
var COLBY = ext(CHE,{ satfat:"Saturated Fat 6g", satfat_dv:"30%", chol:"25mg", chol_dv:"8%",
  sodium:"170mg", sodium_dv:"7%", protein:"7g", calcium:"Calcium 194mg", potassium:"Potassium 36mg",
  ingredients:"INGREDIENTS: PASTEURIZED MILK, CHEESE CULTURES, SALT, ENZYMES, ANNATTO VEGETABLE COLOR." });
var GOU = ext(CHE,{ cal:"100", totfat:"8g", totfat_dv:"10%", sodium:"230mg", sodium_dv:"10%",
  sugars:"1g", protein:"7g", calcium:"Calcium 198mg", potassium:"Potassium 34mg",
  ingredients:"INGREDIENTS: PASTEURIZED MILK, CHEESE CULTURES, SALT, ENZYMES, ANNATTO VEGETABLE COLOR" });
// ^ Gouda's ingredient line has NO terminal period, faithful to its spec sheet. Artwork with no
//   period PASSES against this; PanelProof never "corrects" toward an assumed period.

var EXPECTED = {
  "Cheddar - Mild (Colored).ai":CHE, "Cheddar - Mild (White).ai":CHE,
  "Colby.ai":COLBY, "Gouda.ai":GOU
  // ...one entry per file, keyed by the exact files[] string
};

#target illustrator
/* PanelProof engine v1.0.0 — READ-ONLY proofer for Adobe Illustrator artwork.
   Companion to Illustrator Data Merge: it checks finished artwork against a source of truth.

   Reads   ~/.panelproof/job.jsxinc   (defines global PANELPROOF_JOB)
   Writes  ~/.panelproof/result.json

   Modes:
     "discover" - dump a template/artwork's text frames + named images (same as Data Merge).
     "proof"    - for each artwork file: count live text frames, read the profile-mapped fields,
                  capture the full document text, and render a PNG proof. NO comparison here —
                  the verdicts are computed by proofreport.js, and the visual read is done by
                  looking at the rendered PNGs.

   This engine NEVER edits or saves artwork. It opens read-only and closes without saving. */
(function () {
  app.userInteractionLevel = UserInteractionLevel.DONTDISPLAYALERTS;
  var HOME = Folder("~").fsName;
  var BASE = HOME + "/.panelproof";

  function readFile(p){ var f=new File(p); f.encoding="UTF-8"; if(!f.exists) return null; f.open("r"); var s=f.read(); f.close(); return s; }
  function writeFile(p,s){ var f=new File(p); f.encoding="UTF-8"; f.open("w"); f.write(s); f.close(); }
  function esc(s){ s=String(s); var o=""; for(var i=0;i<s.length;i++){ var c=s.charAt(i),k=s.charCodeAt(i);
    if(c=='"')o+='\\"'; else if(c=='\\')o+='\\\\'; else if(c=='\n')o+='\\n'; else if(c=='\r')o+='\\r'; else if(c=='\t')o+='\\t';
    else if(k<32)o+='\\u'+('0000'+k.toString(16)).slice(-4); else o+=c; } return o; }
  function J(v){
    if(v===null||v===undefined) return "null";
    var t=typeof v;
    if(t=="number"||t=="boolean") return String(v);
    if(t=="string") return '"'+esc(v)+'"';
    if(v instanceof Array){ var a=[]; for(var i=0;i<v.length;i++) a.push(J(v[i])); return "["+a.join(",")+"]"; }
    var p=[]; for(var k in v){ if(v.hasOwnProperty(k)) p.push('"'+esc(k)+'":'+J(v[k])); } return "{"+p.join(",")+"}";
  }
  function fontRuns(f){
    var chars=f.textRange.characters, runs=[], cur=null, str="";
    for(var k=0;k<chars.length;k++){ var fn; try{ fn=chars[k].characterAttributes.textFont.name; }catch(e){ fn="?"; }
      if(fn!==cur){ if(cur!==null) runs.push({font:cur,text:str}); cur=fn; str=String(chars[k].contents); } else str+=String(chars[k].contents); }
    if(cur!==null) runs.push({font:cur,text:str}); return runs;
  }
  function renderDoc(d, dir, scale){
    var folder=new Folder(dir); if(!folder.exists) folder.create();
    var opts=new ExportOptionsPNG24();
    opts.antiAliasing=true; opts.transparency=false; opts.artBoardClipping=true;
    opts.horizontalScale=scale; opts.verticalScale=scale;
    var safe=String(d.name).replace(/\.(ai|pdf|eps|svg)$/i,"").replace(/[^A-Za-z0-9]/g,"_");
    var dest=new File(dir+"/"+safe+".png");
    d.exportFile(dest, ExportType.PNG24, opts);
    return { png:dest.fsName, exists:dest.exists };
  }

  var src=readFile(BASE+"/job.jsxinc");
  if(src===null){ writeFile(BASE+"/result.json", J({ok:false,error:"missing job.jsxinc"})); return; }
  eval(src);
  var JOB=PANELPROOF_JOB;
  var result={ ok:true, mode:JOB.mode, ts:(new Date()).toString() };

  try{
    if(JOB.mode=="discover"){
      var d=app.open(new File(JOB.template));
      var tf=d.textFrames, frames=[];
      for(var i=0;i<tf.length;i++){ var f=tf[i], pos; try{pos=f.position;}catch(e){pos=[0,0];}
        frames.push({ i:i, contents:String(f.contents), x:Math.round(pos[0]), y:Math.round(pos[1]), runs:fontRuns(f) }); }
      var pls=d.placedItems, images=[];
      for(var p2=0;p2<pls.length;p2++){ images.push({ index:p2, name:String(pls[p2].name) }); }
      result.template=JOB.template; result.frameCount=tf.length; result.frames=frames; result.images=images;
      d.close(SaveOptions.DONOTSAVECHANGES);
      writeFile(BASE+"/result.json", J(result)); return;
    }

    if(JOB.mode=="proof"){
      result.inputDir=JOB.inputDir||""; result.profile=JOB.profile||{fields:[]};
      result.expected=JOB.expected||{}; result.products=[];
      result.fdaCheck=(JOB.fdaCheck===true);
      var inDir=JOB.inputDir||"";
      var renderDir=JOB.renderDir || (inDir ? inDir+"/_proof_previews" : BASE+"/_proof_previews");
      result.renderDir=renderDir;
      var files=JOB.files||[];
      var fields=(JOB.profile&&JOB.profile.fields)?JOB.profile.fields:[];
      for(var fx=0; fx<files.length; fx++){
        var fileName=files[fx], rec={ file:fileName }, d2;
        try{
          var path = inDir ? (inDir+"/"+fileName) : fileName;
          d2=app.open(new File(path));
          var tc=d2.textFrames.length;
          rec.liveTextFrames=tc;
          var mapped={};
          for(var mi=0; mi<fields.length; mi++){ var fld=fields[mi];
            if(fld.frame!=null && fld.frame<tc){ try{ mapped[fld.key]=String(d2.textFrames[fld.frame].contents); }catch(e){} } }
          rec.mapped=mapped;
          var ft=[]; for(var ti=0; ti<tc; ti++){ try{ ft.push(String(d2.textFrames[ti].contents)); }catch(e){} }
          rec.fullText=ft.join("\n");
          if(JOB.render!==false){ rec.render=renderDoc(d2, renderDir, JOB.renderScale||300); }
          d2.close(SaveOptions.DONOTSAVECHANGES);
        }catch(ep){ rec.error=String(ep); try{ if(d2) d2.close(SaveOptions.DONOTSAVECHANGES); }catch(e2){} }
        result.products.push(rec);
        writeFile(BASE+"/result.json", J(result));
      }
      writeFile(BASE+"/result.json", J(result)); return;
    }

    result.ok=false; result.error="unknown mode: "+JOB.mode;
    writeFile(BASE+"/result.json", J(result));
  }catch(e){ result.ok=false; result.error=String(e); writeFile(BASE+"/result.json", J(result)); }
})();

#!/usr/bin/env node
/* PanelProof report generator. Reads ~/.panelproof/result.json (actual content + the expected
   spec + profile, all echoed by the engine), computes four-tier verdicts, writes report.html,
   and prints a concise summary to stdout.

   Verdicts:
     pass     - the mapped frame matches the spec exactly (after light normalization)
     present  - the value isn't an exact field match but appears in the document text
                (cross-format / reflowed); placement should be confirmed on the render
     review   - cannot be checked here: no live text (outlined/raster), no spec value, or image
     fail     - the spec value is not found in the artwork at all
   The visual reader (looking at the rendered PNGs) resolves every 'review' and confirms 'present'. */
const fs=require('fs'), os=require('os'), path=require('path');
const BASE=path.join(os.homedir(),'.panelproof');
const RES=path.join(BASE,'result.json'), OUT=path.join(BASE,'report.html');
function esc(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
let r; try{ r=JSON.parse(fs.readFileSync(RES,'utf8')); }catch(e){ fs.writeFileSync(OUT,'<h1>No result.json</h1>'); process.exit(0); }

function norm(s){
  return String(s==null?'':s)
    .replace(/[\u2018\u2019\u02BC]/g,"'").replace(/[\u201C\u201D]/g,'"')
    .replace(/[\u2013\u2014]/g,'-').replace(/\u00B5/g,'\u03BC')   // micro sign -> greek mu
    .replace(/\s+/g,' ').trim();
}
function reEsc(s){ return s.replace(/[.*+?^${}()|[\]\\]/g,'\\$&'); }
function tokenPresent(haystack, needle){
  const n=norm(needle); if(!n) return false;
  // value not flanked by another digit (so "0g" doesn't match inside "10g")
  const re=new RegExp('(^|[^0-9])'+reEsc(n)+'([^0-9]|$)');
  return re.test(norm(haystack));
}

const products=r.products||[], expectedAll=r.expected||{};

// ---- optional FDA self-check (advisory): recompute %DV from the printed amount ----
// Catches an internal inconsistency in the spec/artwork itself (e.g. a wrong %DV on the sheet).
// Never changes a content verdict; it is reported as a separate advisory line.
const DV={ totfat:78, satfat:20, chol:300, sodium:2300, carb:275, fiber:28, addsugars:50, vitd:20, calcium:1300, iron:18, potassium:4700 };
const DVPAIRS=[['totfat','totfat_dv'],['satfat','satfat_dv'],['chol','chol_dv'],['sodium','sodium_dv'],['carb','carb_dv'],['fiber','fiber_dv'],['addsugars','addsugars_dv'],['vitd','vitd_dv'],['calcium','calcium_dv'],['iron','iron_dv'],['potassium','potassium_dv']];
function amt(s){ if(s==null) return null; const m=String(s).match(/(\d+(?:\.\d+)?)\s*(mcg|mg|g)?/i); return m?{v:parseFloat(m[1])}:null; }
function pctOf(s){ if(s==null) return null; const m=String(s).match(/(\d+(?:\.\d+)?)\s*%/); return m?parseFloat(m[1]):null; }
function fdaSelfCheck(vals){
  const checked=[], issues=[];
  for(const pair of DVPAIRS){ const ak=pair[0], dk=pair[1];
    if(vals[ak]==null || vals[dk]==null) continue;
    const a=amt(vals[ak]), printed=pctOf(vals[dk]); const dv=DV[ak];
    if(!a || printed==null || !dv) continue;
    const computed=Math.round(a.v/dv*100); const ok=(computed===printed);
    const row={nutrient:ak, amount:String(vals[ak]), printedDV:printed, computedDV:computed, ok};
    checked.push(row); if(!ok) issues.push(row);
  }
  return {checked, issues};
}
let fp=0, fr=0, ff=0;                 // file tallies: pass, review, fail
let vp=0, vpr=0, vrev=0, vf=0;        // field tallies
const fileResults=[];

for(const p of products){
  const exp=expectedAll[p.file]||{};
  const keys=Object.keys(exp);
  const rows=[]; let nfail=0, nrev=0, npresent=0;
  const noLiveText = !p.error && (p.liveTextFrames===0);
  if(p.error){
    fileResults.push({file:p.file, status:'ERROR', note:p.error, rows:[], render:p.render});
    ff++; continue;
  }
  for(const k of keys){
    const e=exp[k]; const a=(p.mapped&&p.mapped[k]!=null)?p.mapped[k]:null;
    let verdict;
    if(noLiveText){ verdict='review'; }
    else if(a!=null && norm(a)===norm(e)){ verdict='pass'; }
    else if(tokenPresent(p.fullText||'', e)){ verdict='present'; }
    else { verdict='fail'; }
    if(verdict==='pass')vp++; else if(verdict==='present'){vpr++;npresent++;}
    else if(verdict==='review'){vrev++;nrev++;} else {vf++;nfail++;}
    rows.push({k, e, a, verdict});
  }
  let status;
  if(nfail>0) status='FAIL';
  else if(noLiveText) status='REVIEW';
  else if(npresent>0) status='PRESENT';
  else status='PASS';
  if(status==='FAIL')ff++; else if(status==='REVIEW'||status==='PRESENT')fr++; else fp++;
  const fda = r.fdaCheck ? fdaSelfCheck(p.mapped||{}) : null;
  fileResults.push({file:p.file, status, noLiveText, liveTextFrames:p.liveTextFrames, rows, render:p.render, fda});
}

/* ---- stdout summary ---- */
console.log(`PROOF: ${products.length} files | ${fp} pass, ${fr} need a look, ${ff} fail`);
console.log(`FIELDS: ${vp} pass, ${vpr} present(confirm), ${vrev} review, ${vf} FAIL`);
for(const f of fileResults){
  if(f.status==='PASS'){ console.log(`[PASS] ${f.file}`); continue; }
  console.log(`[${f.status}] ${f.file}${f.noLiveText?'  (no live text - read the render)':''}`);
  for(const row of (f.rows||[])){
    if(row.verdict==='fail') console.log(`   FAIL ${row.k}: expected [${row.e}] found [${row.a!=null?row.a:'(not in artwork)'}]`);
    if(row.verdict==='present') console.log(`   present ${row.k}: [${row.e}] (confirm placement on render)`);
  }
  if(f.render&&f.render.exists) console.log(`   render: ${f.render.png}`);
}
if(r.fdaCheck){
  let nf=0, ni=0;
  for(const f of fileResults){ if(f.fda){ nf+=f.fda.checked.length; ni+=f.fda.issues.length; } }
  console.log(`FDA self-check (advisory): ${nf} %DV recomputed, ${ni} discrepanc${ni===1?'y':'ies'}`);
  for(const f of fileResults){ if(f.fda && f.fda.issues.length){ console.log(`   [${f.file}]`);
    for(const x of f.fda.issues) console.log(`     ${x.nutrient}: printed ${x.printedDV}% but ${x.amount} recomputes to ${x.computedDV}%`); } }
}

/* ---- HTML ---- */
const css=`body{background:#0e0f12;color:#e7e9ee;font:14px/1.5 -apple-system,Segoe UI,sans-serif;margin:0;padding:32px}
h1{font-size:20px;margin:0 0 4px}.sub{color:#9aa0ad;margin:0 0 22px;font-size:13px}
.summary{background:#16181d;border:1px solid #262a33;border-radius:10px;padding:16px 18px;margin:0 0 18px}
.card{background:#16181d;border:1px solid #262a33;border-radius:10px;padding:14px 18px;margin:0 0 12px}
.row{display:flex;align-items:center;gap:10px;flex-wrap:wrap}.name{font-weight:600;font-size:15px}
.pill{font-size:12px;font-weight:700;padding:2px 9px;border-radius:999px}
.pass{background:#10331f;color:#5fd38a;border:1px solid #1d5e39}
.present{background:#102a3a;color:#6fb6e0;border:1px solid #1d4a6b}
.review{background:#33270f;color:#e7c15f;border:1px solid #6b551d}
.fail{background:#3a1414;color:#f08a8a;border:1px solid #6b1d1d}
table{border-collapse:collapse;width:100%;margin-top:8px;font-size:12.5px}
td,th{border-bottom:1px solid #23262e;padding:4px 8px;text-align:left;vertical-align:top}
th{color:#9aa0ad}.muted{color:#9aa0ad}.thumb{margin-top:10px;max-width:300px;border:1px solid #2a2e37;border-radius:6px;background:#fff}
.badV td{color:#f0a0a0}.preV td{color:#a9d3ee}`;
const vpill={pass:'pass',present:'present',review:'review',fail:'fail'};
let h=[`<h1>PanelProof &mdash; proof report</h1>`,
  `<p class="sub">${esc(r.ts||'')} &middot; artwork checked against the supplied spec (source of truth)</p>`];
h.push(`<div class="summary"><div class="row"><span class="name">${products.length} files</span>`+
  `<span class="pill pass">${fp} pass</span>`+
  (fr?`<span class="pill review">${fr} need a look</span>`:'')+
  (ff?`<span class="pill fail">${ff} fail</span>`:'')+
  `</div><p class="muted" style="margin-top:8px">${vp} fields pass &middot; ${vpr} present (confirm placement) &middot; ${vrev} review (visual) &middot; ${vf} fail</p>`+
  `<p class="muted">Read-only: PanelProof never edits artwork. 'Review' and 'present' are resolved by looking at the render.</p></div>`);
for(const f of fileResults){
  const cls=(f.status==='FAIL')?'fail':(f.status==='PASS')?'pass':(f.status==='PRESENT')?'present':'review';
  h.push(`<div class="card"><div class="row"><span class="name">${esc(f.file)}</span><span class="pill ${cls}">${esc(f.status)}</span>`+
    (f.noLiveText?`<span class="muted">no live text (outlined/raster) &mdash; verify on render</span>`:'')+`</div>`);
  if(f.note) h.push(`<p class="muted">${esc(f.note)}</p>`);
  const show=(f.rows||[]).filter(x=>x.verdict==='fail'||x.verdict==='present');
  if(show.length){
    h.push(`<table><tr><th>field</th><th>expected (spec)</th><th>found (artwork)</th><th>verdict</th></tr>`);
    for(const row of show){ const rc=row.verdict==='fail'?'badV':'preV';
      h.push(`<tr class="${rc}"><td>${esc(row.k)}</td><td>${esc(row.e)}</td><td>${esc(row.a!=null?row.a:'(not in artwork)')}</td><td>${esc(row.verdict)}</td></tr>`); }
    h.push(`</table>`);
  }
  if(f.render&&f.render.exists) h.push(`<div><img class="thumb" src="file://${esc(f.render.png)}"></div>`);
  if(f.fda && f.fda.checked.length){ const bad=f.fda.issues.length;
    h.push(`<div style="margin-top:10px;font-size:12px;color:${bad?'#e7c15f':'#7a8190'}">FDA %DV self-check (advisory): ${f.fda.checked.length} recomputed, ${bad} discrepanc${bad===1?'y':'ies'}</div>`);
    if(bad){ h.push(`<table><tr><th>nutrient</th><th>amount</th><th>printed %DV</th><th>recomputed</th></tr>`);
      for(const x of f.fda.issues) h.push(`<tr class="badV"><td>${esc(x.nutrient)}</td><td>${esc(x.amount)}</td><td>${esc(x.printedDV)}%</td><td>${esc(x.computedDV)}%</td></tr>`);
      h.push(`</table>`); } }
  h.push(`</div>`);
}
fs.writeFileSync(OUT,`<!doctype html><meta charset=utf-8><title>PanelProof report</title><style>${css}</style><body>${h.join('')}</body>`);
